INSERT INTO "public"."iris_chat_messages" ("id", "user_id", "role", "content", "metadata", "created_at") VALUES
	('da8074ad-476c-40fc-b23d-0f7d4028adf5', 'e4ca6b1e-82d0-43c4-9e13-e1704c0d7a55', 'user', 'hello', NULL, '2026-03-15 00:12:08.247084+00'),
	('f223667b-911a-479f-a8bf-68a5e18e1c9e', 'e4ca6b1e-82d0-43c4-9e13-e1704c0d7a55', 'assistant', 'Hello Sedict Game. How are you today? Is there anything specific I can help you with regarding the building or your lease?', '{"model": "llama-3.1-8b-instant", "tokens": 218}', '2026-03-15 00:12:08.247084+00'),
	('c151adf9-71f1-4959-9159-e13c469575b9', 'e4ca6b1e-82d0-43c4-9e13-e1704c0d7a55', 'user', 'when will be my next rent due?', NULL, '2026-03-15 00:12:24.74517+00'),
	('590b1f7c-c7c5-446b-a294-eb81bbb08e2d', 'e4ca6b1e-82d0-43c4-9e13-e1704c0d7a55', 'assistant', 'To check your next rent due date, I''ll need to look up your lease information. Could you please confirm your lease start date? Alternatively, I can check with our accounting department to verify the details. If you''d like, I can send you a reminder for the upcoming payment.', '{"model": "llama-3.1-8b-instant", "tokens": 293}', '2026-03-15 00:12:24.74517+00'),
	('acacacac-acac-acac-acac-acacacacac01', '33333333-3333-3333-3333-333333333333', 'user', 'Can I pay my rent via GCash this month?', '{"topic": "payments"}', '2026-03-17 00:01:23.072356+00'),
	('acacacac-acac-acac-acac-acacacacac02', '33333333-3333-3333-3333-333333333333', 'assistant', 'Yes. GCash is enabled for your active lease.', '{"topic": "payments", "confidence": "high"}', '2026-03-17 00:01:31.072356+00'),
	('506b7049-ff4b-48ac-bfef-b82629fafa67', '33333333-3333-3333-3333-333333333333', 'user', 'are there any vacant units in my apartment right now? I thinking of referring my friend to rent', NULL, '2026-03-18 02:10:30.323412+00'),
	('33285a29-ccf3-4424-9205-b4cbd15d0013', '33333333-3333-3333-3333-333333333333', 'assistant', 'I can check on available units for you. However, I don''t have real-time information on vacant units. I recommend contacting the leasing office directly for the most up-to-date information on available units. Would you like me to provide you with their contact details?', '{"model": "llama-3.1-8b-instant", "tokens": 561}', '2026-03-18 02:10:30.323412+00'),
	('c08992b7-82eb-45fd-9874-d0558eb1b56b', '33333333-3333-3333-3333-333333333333', 'user', 'wassup', NULL, '2026-03-23 03:18:59.846647+00'),
	('4ebc3ff9-b24b-479d-8e4f-83b3a48405d7', '33333333-3333-3333-3333-333333333333', 'assistant', 'Not much, just checking in to see if you need any help or have any questions about Maple Grove Residences. Is there anything I can assist you with today?', '{"model": "llama-3.1-8b-instant", "tokens": 607}', '2026-03-23 03:18:59.846647+00'),
	('6e3ad796-a65b-4f18-8324-fbb2422d7450', '33333333-3333-3333-3333-333333333333', 'user', 'how''s my rent status?', NULL, '2026-03-23 03:19:40.205043+00'),
	('2fb60036-d3c5-44e8-958e-6ae3ed2b19f4', '33333333-3333-3333-3333-333333333333', 'assistant', 'Your rent status is up to date. As per our records, you''ve made the payment of ₱12,000 on March 16, 2026. Your next payment due date is on April 5, 2026.', '{"model": "llama-3.1-8b-instant", "tokens": 671}', '2026-03-23 03:19:40.205043+00'),
	('964cf303-ca4e-46cd-8b4d-d10d0fb9a616', '33333333-3333-3333-3333-333333333333', 'user', 'What about my bills? Do i have any pending bills?', NULL, '2026-03-23 03:21:52.70134+00'),
	('da440ae5-8f1e-436b-a402-70a0f432edfa', '33333333-3333-3333-3333-333333333333', 'assistant', 'Since your rent payment is due on the 5th of every month, and you''ve already made the payment on March 16, 2026, it seems like you''re on track. However, I don''t have information on other bills such as electricity, water, or internet. These are typically managed directly with the service providers. If you''re concerned about any outstanding bills, I suggest checking your individual accounts or contacting the respective service providers for more information.', '{"model": "llama-3.1-8b-instant", "tokens": 786}', '2026-03-23 03:21:52.70134+00'),
	('3fdd2b58-37f4-4bba-8097-d94b589f00d0', '33333333-3333-3333-3333-333333333333', 'user', 'can you tell me about iReside', NULL, '2026-03-23 03:24:09.095893+00'),
	('c2a3d250-26ec-4270-82eb-fe6737b1d0c1', '33333333-3333-3333-3333-333333333333', 'assistant', 'iReside is the company that manages Maple Grove Residences, where you''re a resident. We''re a property management company that provides a range of services to residents, including lease management, maintenance requests, and communication. Our goal is to make your living experience at Maple Grove Residences as comfortable and convenient as possible. If you have any questions or concerns, feel free to reach out to me or our dedicated team.', '{"model": "llama-3.1-8b-instant", "tokens": 888}', '2026-03-23 03:24:09.095893+00'),
	('ac3d0000-0000-0000-0000-000000000001', '33333333-3333-3333-3333-333333333336', 'assistant', 'Reminder sent. You can tap Pay Now to open checkout immediately.', '{"topic": "payments", "paymentId": "d3d30000-0000-0000-0000-000000000002", "workflowStatus": "reminder_sent"}', '2026-04-23 11:39:37.100179+00'),
	('ac3d0000-0000-0000-0000-000000000002', '33333333-3333-3333-3333-333333333341', 'assistant', 'Your GCash proof is now under review by the landlord.', '{"topic": "payments", "paymentId": "d3d30000-0000-0000-0000-000000000004", "workflowStatus": "under_review"}', '2026-04-23 09:39:37.100179+00'),
	('ac3d0000-0000-0000-0000-000000000003', '33333333-3333-3333-3333-333333333342', 'assistant', 'Your previous submission was rejected with a reason. You can resubmit corrected proof on the same invoice.', '{"topic": "payments", "paymentId": "d3d30000-0000-0000-0000-000000000006", "workflowStatus": "rejected"}', '2026-04-23 00:39:37.100179+00'),
	('ac3d0000-0000-0000-0000-000000000004', '33333333-3333-3333-3333-333333333343', 'assistant', 'In-person intent is active for this invoice. Landlord can confirm directly from the transaction screen.', '{"topic": "payments", "paymentId": "d3d30000-0000-0000-0000-000000000008", "workflowStatus": "awaiting_in_person"}', '2026-04-23 13:39:37.100179+00'),
	('ac3d0000-0000-0000-0000-000000000005', '33333333-3333-3333-3333-333333333344', 'assistant', 'Partial payment was accepted and your remaining balance is still tracked on the ledger.', '{"topic": "payments", "amountTag": "partial", "paymentId": "d3d30000-0000-0000-0000-00000000000a", "workflowStatus": "confirmed"}', '2026-04-22 17:39:37.100179+00');
